# Deobfuscated high-level version

Here’s a condensed readable rewrite of the real logic:

```js
const settings = {
  maxParticles: 4000,
  frictionCoefficient: 0.004,
  damping: 0.92,
  centeringForce: 0.0003,
  streamMax: 40,
  zoomDecay: 0.04,
  cameraLerp: 0.06
};

const nodes = [
  { id: 'hub', label: 'hub', r: 26, x: 400, y: 300, vx: 0, vy: 0 },
  { id: 'alpha', label: 'alpha', r: 16, x: 500, y: 200, vx: 0, vy: 0 },
  { id: 'beta', label: 'beta', r: 16, x: 300, y: 400, vx: 0, vy: 0 },
  { id: 'gamma', label: 'gamma', r: 14, x: 250, y: 180, vx: 0, vy: 0 },
  { id: 'delta', label: 'delta', r: 14, x: 550, y: 380, vx: 0, vy: 0 },
  { id: 'epsilon', label: 'epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

const links = [
  { a: 'hub', b: 'alpha', rest: 160, k: 0.006 },
  { a: 'hub', b: 'beta', rest: 160, k: 0.005 },
  { a: 'hub', b: 'gamma', rest: 170, k: 0.004 },
  { a: 'hub', b: 'delta', rest: 170, k: 0.004 },
  { a: 'hub', b: 'epsilon', rest: 180, k: 0.003 },
  { a: 'alpha', b: 'beta', rest: 200, k: 0.002 },
  { a: 'gamma', b: 'delta', rest: 220, k: 0.002 },
  { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

const particles = [];
const camera = { x: 400, y: 300, zoom: 1 };
const cameraTarget = { x: 400, y: 300, zoom: 1 };
let frame = 0;

function findNode(id) {
  return nodes.find(n => n.id === id) || null;
}

function updateNodes() {
  // repulsion
  for (let i = 0; i < nodes.length; i++) {
    for (let j = i + 1; j < nodes.length; j++) {
      const A = nodes[i], B = nodes[j];
      const dx = A.x - B.x;
      const dy = A.y - B.y;
      const dist = Math.sqrt(dx * dx + dy * dy) || 1;
      const force = settings.frictionCoefficient / (dist * dist);
      const fx = dx / dist * force;
      const fy = dy / dist * force;

      A.vx += fx; A.vy += fy;
      B.vx -= fx; B.vy -= fy;
    }
  }

  // springs
  for (const link of links) {
    const A = findNode(link.a);
    const B = findNode(link.b);
    if (!A || !B) continue;

    const dx = B.x - A.x;
    const dy = B.y - A.y;
    const dist = Math.sqrt(dx * dx + dy * dy) || 1;
    const stretch = dist - link.rest;
    const force = link.k * stretch;

    const fx = dx / dist * force;
    const fy = dy / dist * force;

    A.vx += fx; A.vy += fy;
    B.vx -= fx; B.vy -= fy;
  }

  // centering + damping + integration
  for (const n of nodes) {
    n.vx += (400 - n.x) * settings.centeringForce;
    n.vy += (300 - n.y) * settings.centeringForce;
    n.vx *= settings.damping;
    n.vy *= settings.damping;
    n.x += n.vx;
    n.y += n.vy;
  }
}

function spawnParticle() {
  if (particles.length >= settings.streamMax) return;
  const src = nodes[Math.floor(Math.random() * nodes.length)];
  const angle = Math.random() * 0.283;
  const speed = 0.3 + Math.random() * 0.707;

  particles.push({
    x: src.x,
    y: src.y,
    vx: Math.cos(angle) * speed,
    vy: Math.sin(angle) * speed,
    age: 0,
    maxAge: 120 + Math.floor(Math.random() * 60),
    size: 0.8 + Math.random() * 0.618 * 0.707
  });
}

function updateParticles() {
  for (let i = particles.length - 1; i >= 0; i--) {
    const p = particles[i];
    p.age++;
    p.x += p.vx;
    p.y += p.vy;
    p.vx *= 0.995;
    p.vy *= 0.995;
    if (p.age > p.maxAge) particles.splice(i, 1);
  }
}

function updateCamera() {
  camera.x += (cameraTarget.x - camera.x) * settings.cameraLerp;
  camera.y += (cameraTarget.y - camera.y) * settings.cameraLerp;
  camera.zoom += (cameraTarget.zoom - camera.zoom) * settings.zoomDecay;
}

function tick() {
  updateNodes();
  if (frame % 3 === 0) spawnParticle();
  updateParticles();
  updateCamera();
  frame++;
}

setInterval(tick, 16);
```

That is basically what the meaningful part is doing.

